@if ($line-height == "auto") {

  // Define how many grid lines each text line should span.
  // By default, we set it to the minimum number of lines necessary
  // in order to contain the defined font-size, +1 for some breathing room.
  // This can be modified with the `$modifier` parameter.
  $lines: ceil($font-size / $inuit-global-baseline) + $modifier + 1;
  $line-height: $lines * $inuit-global-baseline;

  line-height: ($line-height / $font-size) $important;
}

@else {

  @if (type-of($line-height) == number or $line-height == "inherit" or $line-height == "normal") {
    line-height: $line-height $important;
  }

  @else if ($line-height != 'none' and $line-height != false) {
    @error "D’oh! `#{$line-height}` is not a valid value for `$line-height`."
  }

}

@function contrast-switch(
  $base-color,
  $dark-color: _fetch-bourbon-setting("contrast-switch-dark-color"),
  $light-color: _fetch-bourbon-setting("contrast-switch-light-color")
) {
  @if not _is-color($base-color) {
    @error "`#{$base-color}` is not a valid color for the `$base-color` " +
      "argument in the `contrast-switch` function.";
  } @else if not _is-color($dark-color) {
    @error "`#{$dark-color}` is not a valid color for the `$dark-color` " +
      "argument in the `contrast-switch` function.";
  } @else if not _is-color($light-color) {
    @error "`#{$light-color}` is not a valid color for the `$light-color` " +
      "argument in the `contrast-switch` function.";
  } @else {
    $-contrast-to-dark: _contrast-ratio($base-color, $dark-color);
    $-contrast-to-light: _contrast-ratio($base-color, $light-color);
    $-prefer-dark: $-contrast-to-dark >= $-contrast-to-light;

    @return if($-prefer-dark, $dark-color, $light-color);
  }
}

@if $force or not private-typography-is-2018-config($config) {
  @return (
    headline-1: map.get($config, display-4),
    headline-2: map.get($config, display-3),
    headline-3: map.get($config, display-2),
    headline-4: map.get($config, display-1),
    headline-5: map.get($config, headline),
    headline-6: map.get($config, title),
    subtitle-1: map.get($config, subheading-2),
    font-family: map.get($config, font-family),

    // These mappings are odd, but body-2 in the 2014 system actually looks closer to subtitle-2
    // in the 2018 system, and subeading-1 in the 2014 system looks more like body-1 in the 2018
    // system.
    subtitle-2: map.get($config, body-2),
    body-1: map.get($config, subheading-1),

    body-2: map.get($config, body-1),
    button: map.get($config, button),
    caption: map.get($config, caption),
    overline:
      map.get($config, overline) or m2-typography.define-typography-level(12px, 32px, 500),
  );
}

// We use this function only in variables.scss because recursive imports are not allowed in Sass anymore.

@function color-contrast-variables($background, $color-contrast-dark, $color-contrast-light, $white, $black, $min-contrast-ratio) {
  $foregrounds: $color-contrast-light, $color-contrast-dark, $white, $black;
  $max-ratio: 0;
  $max-ratio-color: null;

  @each $color in $foregrounds {
    $contrast-ratio: contrast-ratio($background, $color);
    @if $contrast-ratio >= $min-contrast-ratio {
      @return $color;
    } @else if $contrast-ratio > $max-ratio {
      $max-ratio: $contrast-ratio;
      $max-ratio-color: $color;
    }
  }

  @warn "Found no color leading to #{$min-contrast-ratio}:1 contrast ratio against #{$background}...";

  @return $max-ratio-color;
}
